// Extract the dataset ID from the Apify webhook payload and fetch the actual data
const input = $input.first().json;
const body = input.body || input;
const source = body.source || 'unknown';

// The webhook payload contains resource.defaultDatasetId
const datasetId = body.resource?.defaultDatasetId;

if (datasetId) {
  // Fetch dataset items from Apify API
  const apiToken = body.resource?.token || '';
  const url = `https://api.apify.com/v2/datasets/${datasetId}/items?format=json`;
  const response = await fetch(url);
  const leads = await response.json();
  return [{ json: { source, leads, datasetId } }];
}

// Fallback: leads sent directly in payload
let rawLeads = body.leads || [];
if (!Array.isArray(rawLeads)) rawLeads = [rawLeads];
return [{ json: { source, leads: rawLeads } }];

// Normalize leads from different Apify actor formats into a single schema
const input = $input.first().json;
const source = input.source || 'unknown';
let rawLeads = input.leads || [];

if (!Array.isArray(rawLeads)) rawLeads = [rawLeads];

const normalized = rawLeads.map(lead => {
  if (source === 'facebook_marketplace') {
    return {
      name: lead.title || lead.name || 'FB Listing',
      price: lead.price,
      address: lead.location || lead.address,
      zip: lead.zipCode || lead.zip,
      phone: lead.sellerPhone || lead.phone,
      email: lead.sellerEmail || lead.email,
      url: lead.url || lead.link,
      source_id: lead.id || lead.url,
      description: lead.description,
      scraped_at: new Date().toISOString(),
    };
  }

  if (source === 'craigslist') {
    return {
      name: lead.title || 'CL Listing',
      price: lead.price,
      address: lead.location || lead.address || lead.neighborhood,
      zip: lead.zip,
      phone: lead.phone,
      email: lead.replyEmail || lead.email,
      url: lead.url || lead.link,
      source_id: lead.pid || lead.id || lead.url,
      description: lead.description || lead.body,
      scraped_at: new Date().toISOString(),
    };
  }

  if (source === 'google_maps') {
    return {
      name: lead.title || lead.name,
      business_name: lead.title || lead.name,
      phone: lead.phone || lead.phoneNumber,
      email: lead.email,
      website: lead.website || lead.url,
      address: lead.address || lead.street,
      zip: lead.postalCode || lead.zip,
      url: lead.url || lead.googleUrl,
      source_id: lead.placeId || lead.cid || lead.url,
      description: lead.description || lead.categoryName,
      rating: lead.totalScore || lead.rating,
      reviews_count: lead.reviewsCount,
      scraped_at: new Date().toISOString(),
    };
  }

  if (source === 'county_appraisal') {
    return {
      name: lead.ownerName || lead.owner || 'Property Owner',
      owner_name: lead.ownerName || lead.owner,
      address: lead.propertyAddress || lead.address,
      zip: lead.zip || lead.zipCode,
      assessed_value: lead.assessedValue || lead.marketValue,
      tax_status: lead.taxStatus || (lead.delinquent ? 'delinquent' : 'current'),
      url: lead.url,
      source_id: lead.parcelId || lead.folio || lead.id,
      description: `Assessed: $${lead.assessedValue || 'N/A'} | Tax: ${lead.taxStatus || 'unknown'}`,
      scraped_at: new Date().toISOString(),
    };
  }

  if (source === 'newspaper') {
    return {
      name: lead.title || lead.headline || 'News Lead',
      article_title: lead.title || lead.headline,
      article_text: lead.text || lead.content || lead.description,
      url: lead.url || lead.link,
      source_id: lead.url || lead.id,
      description: (lead.text || lead.description || '').slice(0, 500),
      published_at: lead.date || lead.publishedAt,
      scraped_at: new Date().toISOString(),
    };
  }

  return {
    name: lead.name || lead.title || 'Unknown',
    phone: lead.phone,
    email: lead.email,
    address: lead.address,
    zip: lead.zip,
    url: lead.url,
    source_id: lead.id || lead.url,
    description: lead.description,
    scraped_at: new Date().toISOString(),
  };
});

return [{ json: { source, leads: normalized } }];

// Deduplicate by source_id within this batch
const input = $input.first().json;
const seen = new Set();
const unique = [];

for (const lead of input.leads) {
  const key = lead.source_id || `${lead.name}_${lead.address}`;
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(lead);
  }
}

return [{ json: { source: input.source, leads: unique, deduped: input.leads.length - unique.length } }];

const response = $input.first().json;
const source = $('Deduplicate').first().json.source;
const total = $('Deduplicate').first().json.leads.length;
const deduped = $('Deduplicate').first().json.deduped;

return [{
  json: {
    status: 'complete',
    source,
    total_scraped: total + deduped,
    duplicates_removed: deduped,
    sent_to_dashboard: total,
    inserted: response.inserted || 0,
    skipped: response.skipped || 0,
    timestamp: new Date().toISOString(),
  }
}];
